class Solution {
public:
    int bestClosingTime(string customers) {
        int n = customers.size();
        int penalty = 0;
        int min_penalty = INT_MAX;
        int best_time = 0;
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j < i; j++) {
                if (customers[j] == 'Y') penalty++;
            }
            for (int j = i; j < n; j++) {
                if (customers[j] == 'N') penalty++;
            }
            if (penalty < min_penalty) {
                min_penalty = penalty;
                best_time = i;
            }
            penalty = 0;
        }
        return best_time;
    }
};
